try {
const raw = $input.first().json;

function findFields(obj) {
  if (!obj || typeof obj !== 'object') return null;
  if (obj.data_fatura !== undefined || obj.destinatario !== undefined || obj.usuario_id !== undefined) {
    return obj;
  }
  return null;
}

function tryParse(val) {
  if (typeof val === 'string') {
    try { return JSON.parse(val); } catch(e) { return null; }
  }
  return (typeof val === 'object' && val !== null) ? val : null;
}

let src = findFields(raw)
  || findFields(tryParse(raw.query))
  || findFields(raw.query)
  || findFields(tryParse(raw.body))
  || findFields(raw.body)
  || findFields(tryParse(raw.input))
  || findFields(raw.input)
  || findFields(raw.arguments)
  || findFields(raw.toolInput)
  || findFields(raw.data)
  || null;

if (!src) {
  for (const key of Object.keys(raw)) {
    const val = tryParse(raw[key]);
    src = findFields(val);
    if (src) break;
  }
}

if (!src) src = raw;

return [{
  json: {
    data_fatura:   src.data_fatura   ?? null,
    numero_fatura: src.numero_fatura ?? null,
    total:         Number(src.total ?? src.valor_total ?? 0),
    destinatario:  src.destinatario  ?? null,
    arquivo_url:   src.arquivo_url   ?? null,
    categoria:     src.categoria     ?? null,
    usuario_id:    src.usuario_id    ?? null,
    _raw_keys:     Object.keys(raw),
    _source:       src === raw ? 'direct' : 'unwrapped'
  }
}];
} catch (e) {
  const raw = $input.first().json;
  return [{ json: {
    success: false,
    error_code: 'NORMALIZE_ERROR',
    message: '[FN - Normaliza Payload] ' + (e.message || 'Erro desconhecido'),
    _raw_keys: Object.keys(raw || {}),
    _raw_sample: JSON.stringify(raw).substring(0, 500)
  }}];
}

try {
const data = $input.first().json;
const erros = [];

if (!data.destinatario || String(data.destinatario).trim() === '') {
  erros.push('destinatario é obrigatório');
}
if (!data.usuario_id || String(data.usuario_id).trim() === '') {
  erros.push('usuario_id é obrigatório');
}
if (isNaN(data.total) || data.total < 0) {
  erros.push('total deve ser um número positivo');
}

return [{
  json: {
    ...data,
    inputs_validos: erros.length === 0,
    erros_validacao: erros
  }
}];
} catch (e) {
  return [{ json: { success: false, error_code: 'CODE_ERROR', message: '[FN - Valida Inputs] ' + (e.message || 'Erro desconhecido') } }];
}

try {
// PATCH C — Infere categoria e prepara dados para movimentacao
const dbResult = $input.first().json;
const dadosNorm = $('FN - Normaliza Payload').first().json;

// Lê resultado de inserir_conta()
let contaResult = dbResult.inserir_conta;
if (typeof contaResult === 'string') {
  try { contaResult = JSON.parse(contaResult); } catch(e) { contaResult = null; }
}

// Não registra movimentação se: conta não inserida, duplicata, ou total zero
const foiInserida = contaResult?.success === true;
if (!foiInserida || Number(dadosNorm.total) <= 0) {
  return [{ json: { ...dbResult, _skip_mov: true, _mov: null } }];
}

const resumo       = contaResult.resumo || {};
const destinatario = resumo.destinatario || dadosNorm.destinatario || '';
const dataFatura   = resumo.data_fatura  || dadosNorm.data_fatura  || new Date().toLocaleDateString('pt-BR');
const valorTotal   = Number(resumo.total || dadosNorm.total || 0);
const usuarioId    = dadosNorm.usuario_id;

// Normaliza texto para inferência — sem acentos, lowercase
function norm(str) {
  return String(str || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();
}

// Inferência genérica por tipo de serviço (não por fornecedor)
// Usa categoria vinda do agente se for válida; senão infere
const VALIDAS = new Set([
  'Alimentação','Transporte','Saúde','Lazer','Educação','Moradia',
  'Vestuário','Viagem','Assinaturas','Pets','Mercado','Outros',
  'Supermercado','Restaurante','Delivery','Padaria / Café',
  'Combustível','Uber / Táxi','Estacionamento','Manutenção Veículo',
  'Transporte Público','Aluguel','Condomínio','Energia Elétrica',
  'Água / Saneamento','Internet / TV','Gás','Farmácia',
  'Médico / Consulta','Plano de Saúde','Academia / Esporte',
  'Mensalidade Escola','Curso / Capacitação','Livros / Material',
  'Compras','Roupas / Calçados','Eletrônicos','Lazer / Entretenimento',
  'Streaming','Viagem / Hotel','Financeiro','Fatura Cartão',
  'Empréstimo / Parcela','Seguro','Investimento','Imposto / Taxa',
  'Serviços','Assinatura','Telefone / Celular','Pet','Doação / Caridade',
  'Outros (despesa)','Salário','Freelance / Serviço','Aluguel Recebido',
  'Investimento / Rendimento','Reembolso','Presente / Doação','Venda',
  'Cashback / Desconto','Outros (receita)'
]);

function buscarValida(raw) {
  const n = norm(raw);
  for (const v of VALIDAS) {
    if (norm(v) === n) return v;
  }
  return null;
}

function inferirCategoria(texto) {
  const t = norm(texto);

  // Telecomunicações e conectividade
  if (/internet|fibra|banda.?larg|wi.?fi|tv.?a.?cabo|cabo/.test(t))
    return 'Internet / TV';
  if (/telefon|celular|movel|chip|sinal|plano.?(cel|mob)/.test(t))
    return 'Telefone / Celular';

  // Energia elétrica
  if (/energia|eletric|kwh|tarifa.?(energ|eletric)|distribuid|concessionar/.test(t))
    return 'Energia Elétrica';

  // Água e saneamento
  if (/agua|esgoto|saneam|abastec|hidromet|tratam.?agua/.test(t))
    return 'Água / Saneamento';

  // Gás
  if (/\bgas\b|glp|botijao|gasoduto/.test(t))
    return 'Gás';

  // Moradia
  if (/aluguel|locac(?!ao.?de.?carro)/.test(t))
    return 'Aluguel';
  if (/condomin|sindico|taxa.?cond/.test(t))
    return 'Condomínio';
  if (/iptu|taxa.?imov/.test(t))
    return 'Imposto / Taxa';

  // Saúde
  if (/plano.?saude|plano.?med|convenio|unimed|amil|hapvida|sulamerica|bradesco.?saude/.test(t))
    return 'Plano de Saúde';
  if (/farmac|drogari|remedio|medicam/.test(t))
    return 'Farmácia';
  if (/medico|medica|consulta|clinica|hospital|odonto/.test(t))
    return 'Médico / Consulta';
  if (/academia|ginasio|crossfit|natacao|esporte/.test(t))
    return 'Academia / Esporte';

  // Educação
  if (/escola|colegio/.test(t))
    return 'Mensalidade Escola';
  if (/faculdad|universid|graduac|pos.?grad|ead|curso|capacitac|idioma/.test(t))
    return 'Curso / Capacitação';

  // Transporte
  if (/combustiv|gasolina|etanol|diesel|posto/.test(t))
    return 'Combustível';
  if (/ipva|licenciamento|dpvat/.test(t))
    return 'Imposto / Taxa';
  if (/seguro.?veic|seguro.?auto/.test(t))
    return 'Seguro';

  // Financeiro
  if (/fatura|cartao.?credito/.test(t))
    return 'Fatura Cartão';
  if (/emprestimo|parcela|financiam/.test(t))
    return 'Empréstimo / Parcela';
  if (/seguro(?!.?veic)(?!.?auto)/.test(t))
    return 'Seguro';
  if (/imposto|darf|ir\b|irpf/.test(t))
    return 'Imposto / Taxa';

  // Assinaturas
  if (/netflix|spotify|amazon.?prime|disney|hbo|globo.?play|paramount|deezer|apple.?tv/.test(t))
    return 'Streaming';
  if (/assinatura|mensalid.?(club|assin|plataform)/.test(t))
    return 'Assinatura';

  // Pets
  if (/pet\b|veterin|racao|animais/.test(t))
    return 'Pet';

  return null;
}

// Prioridade: categoria do agente > inferência pelo destinatário > 'Outros (despesa)'
const catAgente = dadosNorm.categoria ? buscarValida(dadosNorm.categoria) : null;
const catFinal  = catAgente
  || inferirCategoria(destinatario)
  || 'Outros (despesa)';

return [{
  json: {
    ...dbResult,
    _skip_mov: false,
    _mov: {
      data_transacao: dataFatura,
      transacao:      'Conta: ' + destinatario,
      categoria:      catFinal,
      entrada:        0,
      saida:          valorTotal,
      usuario_id:     usuarioId
    }
  }
}];
} catch (e) {
  return [{ json: { success: false, error_code: 'CODE_ERROR', message: '[FN - Infere Categoria] ' + (e.message || 'Erro desconhecido'), _skip_mov: true, _mov: null } }];
}

